sql:
SELECT SUM(savings_value) 
FROM savings 
WHERE project_id = 1 AND unit = 'kWh';

SELECT AVG(actual_cost) 
FROM projects 
WHERE agency_id = (SELECT agency_id FROM agencies WHERE agency_name = 'specific_agency_name');

SELECT COUNT(project_id)
FROM savings
WHERE savings_value > (SELECT AVG(savings_value) FROM savings);

external_knowledge:
- "thirsting for more than a thousand kilowatt-hours of energy" refers to projects with a consumption value > 1000 kWh;
- "names" indicates the titles of the projects;
- "tales" are the descriptions of the projects;
- "flavors" refer to the types of the projects;
- "homelands" are the locations of the projects.

sql:
SELECT DISTINCT l.location_name AS department_name
FROM projects p
JOIN locations l ON p.location_id = l.location_id;

SELECT location_name 
FROM locations 
WHERE location_id NOT IN (SELECT location_id FROM projects);
